INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the supreme law of the Philippines?', '["The 1987 Constitution", "The Civil Code", "The Revised Penal Code", "The Administrative Code"]', 'A', 'The 1987 Constitution of the Philippines is the supreme law of the land, ratified on February 2, 1987, during the presidency of Corazon Aquino.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('How many branches does the Philippine government have?', '["Three", "Two", "Four", "Five"]', 'A', 'The Philippine government has three branches: the Executive (President), the Legislative (Congress), and the Judicial (Supreme Court and lower courts).', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('Who is the head of the Executive Branch of the Philippine government?', '["The President", "The Chief Justice", "The Senate President", "The Speaker of the House"]', 'A', 'The President of the Philippines is the head of the Executive Branch, serving as both head of state and head of government.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the term of office of the Philippine President?', '["Six years, no re-election", "Six years with one re-election", "Four years with two re-elections", "Five years, no re-election"]', 'A', 'The Philippine President serves a single six-year term and is not eligible for re-election (Section 4, Article VII, 1987 Constitution).', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the Philippine Legislative Branch called?', '["Congress", "Parliament", "National Assembly", "Senate"]', 'A', 'The Legislative Branch of the Philippines is called Congress, which is bicameral and consists of the Senate and the House of Representatives.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('How many members does the Philippine Senate have?', '["24", "12", "50", "300"]', 'A', 'The Philippine Senate has 24 members, elected at-large (nationwide). Senators serve six-year terms, with half elected every three years.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the term of office of a Philippine Senator?', '["Six years, maximum two consecutive terms", "Four years, maximum three terms", "Three years, unlimited terms", "Six years, unlimited terms"]', 'A', 'Philippine senators serve six-year terms and may serve a maximum of two consecutive terms (12 consecutive years total).', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('Which article of the 1987 Philippine Constitution contains the Bill of Rights?', '["Article III", "Article I", "Article II", "Article IV"]', 'A', 'Article III of the 1987 Philippine Constitution contains the Declaration of Rights (Bill of Rights), protecting fundamental civil liberties.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the constitutional right that protects citizens from unreasonable searches and seizures?', '["Right to privacy and security of home", "Right to free speech", "Right to due process", "Right to equal protection"]', 'A', 'Section 2, Article III protects people''s right to be secure in their persons, houses, papers, and effects against unreasonable searches and seizures.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the principle of separation of powers?', '["Each branch of government has distinct and independent powers", "The President controls all branches", "Congress and the courts have equal power", "The military oversees all branches"]', 'A', 'Separation of powers divides government authority among the three branches (executive, legislative, judicial) so that no single branch has absolute power.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the system where each branch of government has the ability to limit the powers of the other branches?', '["Checks and balances", "Separation of powers", "Federalism", "Judicial review"]', 'A', 'Checks and balances is a system where each branch of government can oversee, limit, and correct the other branches to prevent concentration of power.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the highest court in the Philippines?', '["Supreme Court", "Court of Appeals", "Regional Trial Court", "Sandiganbayan"]', 'A', 'The Supreme Court is the highest court in the Philippines, composed of a Chief Justice and 14 Associate Justices.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the term of office of a member of the House of Representatives?', '["Three years, maximum three consecutive terms", "Six years, maximum two terms", "Four years, unlimited terms", "Three years, unlimited terms"]', 'A', 'Members of the House of Representatives serve three-year terms and may serve a maximum of three consecutive terms (9 consecutive years).', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What constitutional body administers Philippine elections?', '["Commission on Elections (COMELEC)", "Commission on Audit (COA)", "Civil Service Commission (CSC)", "Office of the Ombudsman"]', 'A', 'The Commission on Elections (COMELEC) is the independent constitutional body responsible for enforcing electoral laws and administering elections in the Philippines.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the minimum age requirement to vote in the Philippines?', '["18 years old", "21 years old", "16 years old", "25 years old"]', 'A', 'Qualified voters must be at least 18 years of age on or before election day (Section 1, Article V, 1987 Constitution).', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the term for the power of the Supreme Court to declare laws unconstitutional?', '["Judicial review", "Judicial power", "Writ of mandamus", "Due process"]', 'A', 'Judicial review is the power of the Supreme Court to review laws and executive actions and declare them unconstitutional if they violate the Constitution.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the basic political unit of the Philippines?', '["Barangay", "Municipality", "Province", "City"]', 'A', 'The barangay is the basic political unit of the Philippines (formerly called barrio). It is the smallest unit of government.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What does the principle of "due process of law" protect?', '["That government must follow fair procedures before depriving a person of life, liberty, or property", "That all laws must be written in English", "That courts must decide cases quickly", "That citizens must obey all government orders"]', 'A', 'Due process (Section 1, Article III) protects people from arbitrary government action. Substantive due process requires fairness in laws; procedural due process requires fair procedures.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the right of habeas corpus?', '["The right to appear before a court to determine if detention is lawful", "The right to remain silent", "The right to an attorney", "The right to vote"]', 'A', 'Habeas corpus (Latin: "you shall have the body") is the right to challenge the legality of one''s detention before a court. It prevents unlawful imprisonment.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('Which article of the 1987 Constitution declares the Philippines as a democratic and republican state?', '["Article II", "Article I", "Article III", "Article IV"]', 'A', 'Article II (Declaration of Principles and State Policies) declares that the Philippines is a democratic and republican state where sovereignty resides in the people.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the civil service in the Philippines?', '["The body of government employees excluding the military", "The Philippine military", "All citizens over 18", "The diplomatic corps"]', 'A', 'The civil service includes all branches and subdivisions of government, excluding the military. The Civil Service Commission (CSC) oversees it.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the Local Government Code of the Philippines?', '["Republic Act 7160", "Republic Act 9160", "Republic Act 7610", "Republic Act 8560"]', 'A', 'The Local Government Code of the Philippines is Republic Act 7160 (1991), which grants local government units broader autonomy and powers.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the function of the Commission on Audit (COA)?', '["Examining and auditing all government accounts and expenditures", "Conducting elections", "Managing government employees", "Enforcing laws"]', 'A', 'The Commission on Audit (COA) is the supreme audit institution of the Philippines, responsible for examining and auditing all government revenues, expenditures, and accounts.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the term for the process by which citizens can directly propose or enact laws?', '["Initiative", "Referendum", "Plebiscite", "Recall"]', 'A', 'Initiative is the process by which citizens can directly propose laws or constitutional amendments by gathering signatures and submitting them for direct vote.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the term for a vote to remove an elected official from office?', '["Recall", "Referendum", "Plebiscite", "Initiative"]', 'A', 'Recall is a process by which voters can remove an elected official from office before the end of their term through a special election.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What does the Equal Protection Clause in the Bill of Rights guarantee?', '["All persons or things similarly situated should be treated alike", "All citizens receive equal property", "Rich and poor receive identical services", "Everyone earns the same wage"]', 'A', 'The Equal Protection Clause (Section 1, Article III) guarantees that all persons or things similarly situated shall be treated alike under the law.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the writ of amparo in Philippine law?', '["A remedy for violations of the right to life, liberty, or security", "A warrant for arrest", "A search warrant", "An order to appear in court"]', 'A', 'The writ of amparo is a remedy for persons whose right to life, liberty, or security is violated or threatened by unlawful acts or omissions of public officials (or private parties in some cases).', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('How is the Philippine Constitution amended or revised?', '["By a constituent assembly, constitutional convention, or people''s initiative", "By the President''s decree", "By Congress alone", "By the Supreme Court"]', 'A', 'Article XVII provides three methods: (1) Constituent Assembly (¾ vote of all Congress members), (2) Constitutional Convention, or (3) People''s Initiative.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the term for the principle that sovereignty resides in the people?', '["Popular sovereignty", "Parliamentary sovereignty", "Judicial sovereignty", "Executive sovereignty"]', 'A', 'Popular sovereignty is the principle that legitimate governmental authority is derived from the consent of the people (Section 1, Article II, 1987 Constitution).', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What constitutional provision protects freedom of speech and expression?', '["Section 4, Article III", "Section 1, Article II", "Section 5, Article III", "Section 12, Article III"]', 'A', 'Section 4 of Article III of the 1987 Constitution protects freedom of speech, expression, press, and peaceful assembly.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the Ombudsman''s role in the Philippines?', '["Investigate and prosecute public officials for misconduct", "Manage elections", "Audit government funds", "Administer civil service exams"]', 'A', 'The Office of the Ombudsman (Tanodbayan) investigates and prosecutes public officials for corruption, misconduct, inefficiency, and other offenses related to public office.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the Sandiganbayan?', '["Anti-graft court that tries cases of public officials", "The highest court in the Philippines", "The military tribunal", "The commercial court"]', 'A', 'The Sandiganbayan is a special anti-graft court that has jurisdiction over criminal and civil cases involving public officials charged with violations of the Anti-Graft and Corrupt Practices Act.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What vote is required for the Senate to ratify international treaties?', '["Two-thirds of all members", "Simple majority", "Three-fourths of all members", "Unanimous vote"]', 'A', 'Under Section 21 of Article VII, treaties and international agreements require concurrence of at least two-thirds of all Senate members to take effect.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the principle of "civilian supremacy over the military"?', '["The military is under the authority and control of civilian government", "The military controls the president", "Civilians can join the military freely", "The military decides on elections"]', 'A', 'Section 3, Article II of the 1987 Constitution establishes civilian supremacy, making the Armed Forces of the Philippines subject to civilian authority.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the presidential veto power?', '["The power of the President to reject bills passed by Congress", "The power to dissolve Congress", "The power to suspend elections", "The power to remove judges"]', 'A', 'The veto power allows the President to reject (veto) bills passed by Congress. Congress can override a veto with a two-thirds vote of all its members.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the constitutional prohibition against bills of attainder?', '["No law shall be passed that singles out a person or group for punishment without trial", "No citizen can be tried twice for the same crime", "No one shall be imprisoned for debt", "All trials must be public"]', 'A', 'A bill of attainder is a legislative act that punishes a person without judicial trial. Article III, Section 22 prohibits such laws in the Philippines.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('Which constitutional right protects an accused person from being tried twice for the same offense?', '["Double jeopardy", "Habeas corpus", "Due process", "Self-incrimination"]', 'A', 'Section 21, Article III protects against double jeopardy — no person shall be twice put in jeopardy of punishment for the same offense.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the constitutional basis for the right to education in the Philippines?', '["Section 1, Article XIV", "Section 1, Article III", "Section 5, Article II", "Section 2, Article XIII"]', 'A', 'Section 1, Article XIV states that the State shall protect and promote the right of all citizens to quality education at all levels.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the term for laws passed by local government units?', '["Ordinances", "Statutes", "Decrees", "Resolutions"]', 'A', 'Ordinances are local laws enacted by the Sanggunian (legislative council) of barangays, municipalities, cities, or provinces.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the Civil Service Commission (CSC)?', '["The central personnel agency of the Philippine government", "The audit body of the government", "The election management body", "The anti-graft court"]', 'A', 'The Civil Service Commission (CSC) is the central personnel agency of the Philippine government, responsible for promoting merit and fitness in government service.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What does Article II, Section 14 of the 1987 Constitution declare about women?', '["The State shall ensure the fundamental equality before the law of women and men", "Women have priority in government jobs", "Women are exempt from military service", "Women have an equal right to vote only"]', 'A', 'Section 14, Article II declares: "The State recognizes the role of women in nation-building, and shall ensure the fundamental equality before the law of women and men."', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('Who has the power of impeachment in the Philippines?', '["The House of Representatives (to impeach) and Senate (to try)", "The Supreme Court alone", "The Senate alone", "Both chambers jointly"]', 'A', 'The House of Representatives has the exclusive power to initiate impeachment cases. The Senate, as the impeachment court, tries and decides impeachment cases.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the constitutional requirement for a search warrant to be issued?', '["Probable cause supported by personal examination of the judge", "A request by any police officer", "Congressional approval", "Presidential order"]', 'A', 'Section 2, Article III requires that search warrants be based on probable cause determined personally by a judge after examination of witnesses under oath.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the principle of "national patrimony" in the Philippine Constitution?', '["Natural resources belong to the State and Filipino citizens", "Foreign companies can own natural resources", "Individual landowners own all minerals", "Local governments own all natural resources"]', 'A', 'Article XII (National Economy and Patrimony) declares that all natural resources are owned by the State, and their exploration and utilization shall be under the full control of the State.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the Philippine Commission on Human Rights?', '["An independent constitutional body that investigates human rights violations", "A court that tries human rights cases", "A branch of the Supreme Court", "A department under the Executive branch"]', 'A', 'The Commission on Human Rights (CHR) is an independent constitutional body created under Section 17, Article XIII to investigate human rights violations in the Philippines.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('In which year was the current Philippine Constitution ratified?', '["1987", "1973", "1935", "1986"]', 'A', 'The 1987 Philippine Constitution was ratified by plebiscite on February 2, 1987, after being drafted by the Constitutional Commission appointed by President Corazon Aquino.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the principle of "state immunity from suit"?', '["The state cannot be sued without its consent", "The state must always win court cases", "Citizens cannot sue the government", "The president is immune from all suits"]', 'A', 'State immunity from suit means the State cannot be sued without its consent. The Philippines has waived this for certain actions through specific legislation.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What are the three independent constitutional commissions in the Philippines?', '["COMELEC, COA, and CSC", "COMELEC, COA, and Ombudsman", "COA, CSC, and Supreme Court", "CHR, COA, and COMELEC"]', 'A', 'The three independent constitutional commissions are the Commission on Elections (COMELEC), Commission on Audit (COA), and Civil Service Commission (CSC).', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What constitutional provision protects freedom of religion?', '["Section 5, Article III", "Section 4, Article III", "Section 1, Article III", "Section 8, Article III"]', 'A', 'Section 5, Article III: "No law shall be made respecting an establishment of religion, or prohibiting the free exercise thereof." This ensures separation of Church and State.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What is the doctrine of "command responsibility"?', '["Superior officers are liable for crimes committed by subordinates under their command if they knew or should have known", "Commanders must follow presidential orders", "Military officers are exempt from civil courts", "Only the direct perpetrator is responsible for crimes"]', 'A', 'Command responsibility holds military/police commanders legally responsible for crimes committed by subordinates if the commander knew or should have known and failed to prevent or punish the acts.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What does the 1987 Constitution say about the death penalty?', '["It prohibits death penalty unless Congress reinstates it for heinous crimes", "It allows death penalty for all crimes", "It permanently abolishes death penalty", "It leaves death penalty to presidential discretion"]', 'A', 'Section 19, Article III: "Neither shall death penalty be imposed, unless, for compelling reasons involving heinous crimes, the Congress hereafter provides for it."', 'Social Studies', 'Philippine Government', 'hard', 'secondary');
